var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"제3 승강장, 탐사조 행드맨 알파, 강하 대기 중.","JPN":"第3昇降機乗り場、探査組ハングドマン、アルファ、降下待機中。","ENG":"Platform 3, Exploration Team Hanged Man Alpha, awaiting descent.","TWN":"3號平台，勘查小隊倒吊人阿爾法，等待下降。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_NOISE"},{"id":"L5_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"시라사키가 이 승강장을 다시 운용할 줄은 몰랐습니다.","JPN":"まさかシラサキがこの昇降機をまた運用する日が来るとは思いませんでしたよ。","ENG":"Didn't think Sirasaki would have this elevator up and running again.","TWN":"沒想到白崎會再次啟動這個平台。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L6_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"오는 길의 철저한 보안상태를 보면, 아무에게나 열어주는 건 아닌 것 같지만 말이죠.","JPN":"ここに来るまでの徹底したセキュリティーの様子だと、誰にでも使わせるわけではないみたいですけどね。","ENG":"Given the tight security we saw on the way here, it doesn't seem like they're opening it for anyone.","TWN":"而且一路上戒備森嚴，似乎不是對所有人開放的。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L7_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"데이터나 아티팩트를 찾아달란 임무는 많이 받아봤지만, 살아있는 사람을 찾는 의뢰는 처음이군.","JPN":"データやアーティファクトを探す任務ならたくさん受けてきたが、生きた人間を探してくる依頼は初めてだ。","ENG":"I've been on many missions finding data or Artifacts, but this is my first time getting a request to find a person.","TWN":"我也接到過不少尋找資料或者人造神器的任務，但要我們去找一個活人，倒還是第一次呢。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L9_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"현상금 사냥 같은 거잖아. 재밌겠네.","JPN":"懸賞金狩りみたいでワクワクするぜ。","ENG":"It's like we're bounty hunting. Sounds fun.","TWN":"聽起來像賞金獵人一樣。很有趣啊。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"다들 이터니움 실드 잔량 점검해. 환경의 가변성을 고려해 최대 48시간 이내 복귀를 목표로 한다.","JPN":"全員、エタニウムシールドの残量を確認して。目的地の環境が予測不可能であることを考慮に入れ、帰還まで48時間をタイムリミットとする。","ENG":"Everyone, check your Eternium shields. Considering the variability of the environment, we aim to return within 48 hours at most.","TWN":"各位，檢查一下永恆之金盾的剩餘容量。考慮到環境的多變性，我們的目標是在48小時內返回。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"점검 끝. 이상 무.","JPN":"点検完了。異常無し。","ENG":"Check complete. All green.","TWN":"檢查完畢。沒有發現異常。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L13_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"그런데, 저 아가씬 정말 슈트를 입지 않는 겁니까?","JPN":"ところで、あのお嬢さんは本当にスーツを着なくていいのですか？","ENG":"Umm, is that girl really not going to wear a suit?","TWN":"對了，那個女孩真的不穿防護服嗎？"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"SAW_REAPER_NULL_CODENAME","text":{"KOREA":"네, 저는 예쁜 옷이 좋거든요.","JPN":"はい、私は可愛い服が好きなので。","ENG":"Yes, I like pretty clothes, you see.","TWN":"沒事啦，我喜歡漂亮的衣服。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SAW_REAPER_NULL_CODENAME","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"우리가 가는 곳은 유원지가 아니다. 카운터라도 최소한의 보호장비는 갖추는 편이 좋아.","JPN":"俺たちが向かっているのは遊園地なんかじゃないんだぞ。いくらカウンターでも最低限の保護装備は備えておいた方がいい。","ENG":"We're not going to a theme park. Even if you're a Counter, it's better to have at least some protective gear.","TWN":"喂，我們不是去遊樂園。就算你是制裁者，也需要一些基本的防護吧？"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"본인이 괜찮다는데 내버려 둬.","JPN":"本人が大丈夫だって言ってんだ、ほっとけ。","ENG":"She says it's fine. Leave her be.","TWN":"她自己都說沒問題，你就別管了。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"칙칙한 우리 꼬락서니 좀 봐. 저 아가씨 덕에 분위기도 한층 밝아지고 좋지 뭐.","JPN":"見ろよ、しみったれた俺たちのざまを。お嬢ちゃんのおかげで、雰囲気も少しは明るくなっていいじゃないか。","ENG":"Look at our gloomy little group. At least she's brightening up the atmosphere a bit.","TWN":"看看我們這副灰暗的模樣。多虧了那位小姐，氣氛才變得明亮、美好起來了啊？"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"…….","JPN":"……","ENG":"...","TWN":"……"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"메인로프 전개 및 좌표 고정기 가동. 리프트드롭 준비 완료.","JPN":"メインロープを展開、座標固定器を稼働、リフトドロップの準備完了。","ENG":"Main rope deployment and coordinate stabilizer activated. Lift drop preparation complete.","TWN":"拉開主繩，啟動座標定位儀。升降準備就緒。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"3… 2… 1…","JPN":"3……2……1……","ENG":"3… 2… 1…","TWN":"3……2……1……"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_EXOSUIT","text":{"KOREA":"강하.","JPN":"降下開始。","ENG":"Descend.","TWN":"開始下降。"},"stage":{"bg":"LIFT","bgm":"UI_DIVE","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_EXOSUIT","face":"UNIT_IDLE"},"R":null}}},{"id":"L27_1","type":"subtitle","speaker":null,"text":{"KOREA":"챔버 대균열 심부. 5층.","JPN":"チェンバー大亀裂深部第5階。","ENG":"Chamber's Grand Dimension Crevice depths. 5th floor.","TWN":"強巴大峽谷深處。地下5層。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L28_1","type":"subtitle","speaker":null,"text":{"KOREA":"강하 완료 후 20분 경과.","JPN":"降下完了してから20分が経過。","ENG":"20 minutes after the descent.","TWN":"距離下降完成，已經過20分鐘。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"베이스포인트 확보 완료.","JPN":"ベース地点の確保完了。","ENG":"Basepoint secured.","TWN":"基點確認完畢。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"R":null}},"sfx":"FX_CUTSCEN_PHONE"},{"id":"L31_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"아직까지 특별한 징후는 없습니다.","JPN":"今のところ変わった兆候はなし。","ENG":"Nothing out of the ordinary yet.","TWN":"目前還沒有特殊跡象。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"통신기를 포함한 장비 몇 개는 맛이 갔군. 다이브 부하를 견디지 못한 것 같아.","JPN":"通信機、その他複数の装備は使用不可になっている。ダイブ時の負荷のせいで壊れたみたいだな。","ENG":"Some equipment is fried. Including the comms. They couldn't withstand the dive strains.","TWN":"包括通訊設備在內的部分裝備已毀壞。似乎無法承受躍入的負荷。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L35_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"상용장비 대부분의 카탈로그 스펙으론 심층 환경을 견디기 힘들 거야.","JPN":"一般装備のカタログスペックでは深層の環境には耐え切れないことが多い。","ENG":"Most commercial equipment isn't sturdy enough to withstand the environment down here.","TWN":"正常，大多數商用裝備的性能無法承受深層環境。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"다행히 중요한 장비들은 멀쩡해. 작업에 큰 문제는 없겠어.","JPN":"幸い、メイン装備に関してはまだ壊れてはいないみたいだな。これなら任務に支障はない。","ENG":"Fortunately, the essentials are good. There shouldn't be any major issues with the operation.","TWN":"幸運的是，重要裝備完好無損。工作上不會有什麼大問題。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L38_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM1","text":{"KOREA":"힉스는 아직 돌아오지 않은 겁니까?","JPN":"ヒックスはまだ戻ってないんですか？","ENG":"Hicks isn't back yet?","TWN":"希克斯還沒回來嗎？"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"C":null,"R":null}}},{"id":"L39_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM2","text":{"KOREA":"브리핑 때는 20분 안으로 복귀하라고 했을 텐데, 벌써부터 제멋대로군.","JPN":"事前の打ち合わせでは20分以内に帰還することになっていたはずだが、さっそく勝手なことをやってくれるぜ。","ENG":"We told her to return within 20 minutes during the briefing. But she's already off doing her own thing.","TWN":"上次聯繫的時候，我告訴她需要在20分鐘內返回，但她好像沒放在心上。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM1","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM2","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"EXOSUIT_FLOOR_NULL_TEAM3","text":{"KOREA":"벌써 침식체들에게 당해버린 건 아니겠지? 그럼 좀 아까운데.","JPN":"もしくは、もう侵食体にやられちまったんじゃねえか？　だとしたら惜しいことしたな。","ENG":"Hope the C.O.s didn't get to her already. That would be a shame.","TWN":"不會被侵蝕體攻擊了吧？那就可惜了。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"EXOSUIT_FLOOR_NULL_TEAM3","face":"UNIT_IDLE"},"R":null}}},{"id":"L43_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"힉스의 태그가 아까부터 한 곳에 멈춰 있어.","JPN":"ヒックスのタグがずっと同じ位置で止まっている。","ENG":"Hicks's tag has been stationary in one spot for a while.","TWN":"希克斯的標籤，從剛剛開始就沒移動過。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"아마 어떤 문제가 생겼고, 통신기가 먹통이란 걸 모르는 상황일 가능성이 높아.","JPN":"おそらく何らかの異常事態に巻き込まれ、通信機が作動しなくなったことに気づいていない可能性が高い。","ENG":"It's likely that something happened, and she's unlikely to be aware that our comms are down.","TWN":"她很有可能遇到了問題，並且也沒有注意到通訊設備失靈。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L45_1","type":"dialog","speaker":"SPENCER_FLOOR_NULL_NULL","text":{"KOREA":"우리가 유도등을 설치하면서 해당 좌표로 이동한다.","JPN":"誘導灯を設置しつつ目的地の座標まで移動する。","ENG":"We'll move to her coordinates while putting down the guiding lights.","TWN":"我們邊安裝引導燈，邊向她所在的位置移動。"},"stage":{"bg":"COUNTERSIDE_PLAIN","bgm":"CUTSCENE_AMBIENT_WIND","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPENCER_FLOOR_NULL_NULL","face":"UNIT_IDLE"},"R":null}}}]`);export{e as default};